// PDF-Bytes (binary) in Base64 umwandeln
const binaryData = $input.first().binary?.data;
if (!binaryData) {
  // Fallback: Body direkt als Buffer
  const body = $input.first().json?.body;
  if (!body) throw new Error('Kein PDF-Inhalt empfangen');
  return [{ json: { pdfBase64: Buffer.from(body).toString('base64') } }];
}
const base64 = binaryData.data;
return [{ json: { pdfBase64: base64 } }];

// Gemini-Antwort parsen
const response = $input.first().json;
const rawText = response?.candidates?.[0]?.content?.parts?.[0]?.text || '';

let jsonText = rawText.trim();
// Markdown-Code-Blöcke entfernen falls vorhanden
if (jsonText.startsWith('```')) {
  jsonText = jsonText.replace(/^```json?\n?/, '').replace(/\n?```$/, '');
}

let extracted;
try {
  extracted = JSON.parse(jsonText);
} catch (e) {
  throw new Error(`JSON-Parsing fehlgeschlagen: ${e.message}\nAntwort: ${rawText.substring(0, 300)}`);
}

const result = {
  rechnungs_nummer:       String(extracted.rechnungs_nummer || 'UNBEKANNT'),
  lieferant:              String(extracted.lieferant || 'UNBEKANNT'),
  betrag:                 parseFloat(extracted.betrag) || 0,
  waehrung:               ['EUR','USD','CHF','GBP'].includes(extracted.waehrung) ? extracted.waehrung : 'EUR',
  datum:                  extracted.datum || new Date().toISOString().split('T')[0],
  eingangskanal:          extracted.eingangskanal || 'Email',
  rechnungspositionen:    Array.isArray(extracted.rechnungspositionen) ? extracted.rechnungspositionen : [],
  ki_extraktion_erfolgreich:  true,
  ki_extraktion_zeitstempel:  new Date().toISOString(),
};

return [{ json: result }];
